"use strict";(self.webpackChunkarticles=self.webpackChunkarticles||[]).push([["5092"],{2495(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"welcome","metadata":{"permalink":"/heiman-docs/es/blog/welcome","source":"@site/blog/2021-08-26-welcome/index.mdx","title":"Welcome to Heiman Technology","description":"Welcome to Heiman Technology! This is the official knowledge base of Heiman Technology, bringing together product documentation, technical solutions, industry news, and company updates.","date":"2021-08-26T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-docs/es/blog/tags/heiman","description":"Heiman Technology news and updates"}],"readingTime":0.74,"hasTruncateMarker":true,"authors":[{"name":"Leo","title":"Heiman Documentation Maintainer","url":"https://github.com/Leo2442926161","page":{"permalink":"/heiman-docs/es/blog/authors/leo"},"socials":{"github":"https://github.com/Leo2442926161"},"imageURL":"/heiman-docs/es/img/leoprofile.jpg","key":"leo"}],"frontMatter":{"slug":"welcome","title":"Welcome to Heiman Technology","authors":["leo"],"tags":["heiman"]},"unlisted":false,"nextItem":{"title":"Heiman Matter Smart Smoke Alarm Officially Launched","permalink":"/heiman-docs/es/blog/mdx-blog-post"}},"content":"Welcome to Heiman Technology! This is the official knowledge base of Heiman Technology, bringing together product documentation, technical solutions, industry news, and company updates.\\n\\n{/* truncate */}\\n\\n## About This Site\\n\\nHeiman Technology is dedicated to providing partners, developers, and customers with one-stop technical resources to help you quickly learn about:\\n\\n- **Product Center** \u2014 Full range of smart fire, smart gas, smart elderly care, and smart sensing products\\n- **Solutions** \u2014 Industry-level smart security solutions\\n- **Technical Documentation** \u2014 API integration guides, SDK usage instructions, installation and deployment manuals\\n- **Industry Insights** \u2014 Cutting-edge trends and policy analysis in smart security\\n\\n## Quick Navigation\\n\\n- View [Product Line](/docs/Product%20line/Smoke%20Sensor) to learn about Heiman\'s product range\\n- Read [Company Overview](/docs/intro) to learn about Heiman\'s development history\\n- Visit [Heiman Official Website](https://www.heiman.com.cn) for more information\\n\\nIf you have any questions, please call customer service hotline **400-8959-500** or contact online customer service."},{"id":"mdx-blog-post","metadata":{"permalink":"/heiman-docs/es/blog/mdx-blog-post","source":"@site/blog/2021-08-01-mdx-blog-post.mdx","title":"Heiman Matter Smart Smoke Alarm Officially Launched","description":"Heiman Technology\'s next-generation Matter smart smoke alarm HS1SA-M has been officially launched, making it one of the first smoke alarm products in the industry to receive Matter 1.2 certification.","date":"2021-08-01T00:00:00.000Z","tags":[{"inline":false,"label":"Matter","permalink":"/heiman-docs/es/blog/tags/matter","description":"Matter protocol related content"},{"inline":false,"label":"Smart Fire Safety","permalink":"/heiman-docs/es/blog/tags/smart-fire","description":"Smart fire safety products and solutions"}],"readingTime":0.69,"hasTruncateMarker":true,"authors":[{"name":"Leo","title":"Heiman Documentation Maintainer","url":"https://github.com/Leo2442926161","page":{"permalink":"/heiman-docs/es/blog/authors/leo"},"socials":{"github":"https://github.com/Leo2442926161"},"imageURL":"/heiman-docs/es/img/leoprofile.jpg","key":"leo"}],"frontMatter":{"slug":"mdx-blog-post","title":"Heiman Matter Smart Smoke Alarm Officially Launched","authors":["leo"],"tags":["matter","smart-fire"]},"unlisted":false,"prevItem":{"title":"Welcome to Heiman Technology","permalink":"/heiman-docs/es/blog/welcome"},"nextItem":{"title":"Heiman Technology Development Milestones","permalink":"/heiman-docs/es/blog/long-blog-post"}},"content":"Heiman Technology\'s next-generation Matter smart smoke alarm HS1SA-M has been officially launched, making it one of the first smoke alarm products in the industry to receive Matter 1.2 certification.\\n\\n{/* truncate */}\\n\\n:::tip\\n\\nHS1SA-M supports four major smart home ecosystems: Apple HomeKit, Amazon Alexa, Google Home, and Samsung SmartThings.\\n\\n:::\\n\\n## Key Features\\n\\n- **Matter 1.2 Certified** \u2014 Cross-brand, cross-ecosystem interoperability\\n- **Photoelectric Smoke Sensing** \u2014 Rapid response to various fire smoke types\\n- **Voice Alarm Alerts** \u2014 Multiple language options for clear hazard communication\\n- **Self-Test Function** \u2014 Periodic self-checks to ensure normal operation\\n- **Remote Notification** \u2014 Real-time push alerts via mobile app\\n\\n## Compatibility\\n\\nHS1SA-M seamlessly integrates with mainstream smart home platforms, allowing users to control and manage it directly via their smartphones without the need for an additional gateway.\\n\\nFor more details, visit [Product Line](/docs/Product%20line/Smoke%20Sensor)."},{"id":"long-blog-post","metadata":{"permalink":"/heiman-docs/es/blog/long-blog-post","source":"@site/blog/2019-05-29-long-blog-post.mdx","title":"Heiman Technology Development Milestones","description":"Since its founding in 2005, Heiman Technology has journeyed over 20 years of development. This article takes you through Heiman\'s key milestones.","date":"2019-05-29T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-docs/es/blog/tags/heiman","description":"Heiman Technology news and updates"}],"readingTime":1.12,"hasTruncateMarker":true,"authors":[{"name":"Leo","title":"Heiman Documentation Maintainer","url":"https://github.com/Leo2442926161","page":{"permalink":"/heiman-docs/es/blog/authors/leo"},"socials":{"github":"https://github.com/Leo2442926161"},"imageURL":"/heiman-docs/es/img/leoprofile.jpg","key":"leo"}],"frontMatter":{"slug":"long-blog-post","title":"Heiman Technology Development Milestones","authors":["leo"],"tags":["heiman"]},"unlisted":false,"prevItem":{"title":"Heiman Matter Smart Smoke Alarm Officially Launched","permalink":"/heiman-docs/es/blog/mdx-blog-post"},"nextItem":{"title":"Heiman Technology Recognized as National \\"Little Giant\\" Enterprise","permalink":"/heiman-docs/es/blog/first-blog-post"}},"content":"Since its founding in 2005, Heiman Technology has journeyed over 20 years of development. This article takes you through Heiman\'s key milestones.\\n\\n{/* truncate */}\\n\\n## 2005 - Company Founded\\n\\nShenzhen Heiman Technology Co., Ltd. was officially established, entering the security and sensing field.\\n\\n## 2006 - International Expansion\\n\\nMultiple products received EU CE certification, and a partnership was established with China Mobile.\\n\\n## 2011 - International Certification Breakthrough\\n\\nMultiple products passed EU EN54-7 and EN14604 certification, marking product quality reaching international advanced standards.\\n\\n## 2012 - Smart Home Transformation\\n\\nThe smart home project was fully launched, transitioning Heiman into a company focused on R&D, production, and sales of smart home products.\\n\\n## 2017 - Major Breakthroughs\\n\\n- Developed China\'s first NB-IoT smoke alarm\\n- Won 2 German Red Dot Design Awards\\n- Obtained MFi certification and Apple manufacturer qualification\\n\\n## 2020 - Capital Boost\\n\\nCompleted Series A funding round with Shenzhen HTI Group as investor, received \\"Guangdong Province Specialized and New SME\\" designation.\\n\\n## 2022 - National Recognition\\n\\nRecognized as a national \\"Little Giant\\" enterprise; K1 series won German Red Dot Design Award.\\n\\n## 2023 - International Standards Leadership\\n\\nHeiman testing laboratory officially passed national CNAS accreditation; smoke alarms and CO alarms were among the first to receive Matter 1.2 certification.\\n\\n## 2024 - Present\\n\\nContinuous innovation, deeply engaged in smart fire safety, smart gas safety, smart elderly care, and smart sensing, providing quality products and services to customers in 100+ countries worldwide."},{"id":"first-blog-post","metadata":{"permalink":"/heiman-docs/es/blog/first-blog-post","source":"@site/blog/2019-05-28-first-blog-post.mdx","title":"Heiman Technology Recognized as National \\"Little Giant\\" Enterprise","description":"In 2022, Heiman Technology was officially recognized as a national \\"Little Giant\\" enterprise (Specialized and New) for its deep technical expertise and innovation capabilities in the smart sensing field.","date":"2019-05-28T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-docs/es/blog/tags/heiman","description":"Heiman Technology news and updates"}],"readingTime":0.48,"hasTruncateMarker":true,"authors":[{"name":"Leo","title":"Heiman Documentation Maintainer","url":"https://github.com/Leo2442926161","page":{"permalink":"/heiman-docs/es/blog/authors/leo"},"socials":{"github":"https://github.com/Leo2442926161"},"imageURL":"/heiman-docs/es/img/leoprofile.jpg","key":"leo"}],"frontMatter":{"slug":"first-blog-post","title":"Heiman Technology Recognized as National \\"Little Giant\\" Enterprise","authors":["leo"],"tags":["heiman"]},"unlisted":false,"prevItem":{"title":"Heiman Technology Development Milestones","permalink":"/heiman-docs/es/blog/long-blog-post"}},"content":"In 2022, Heiman Technology was officially recognized as a national \\"Little Giant\\" enterprise (Specialized and New) for its deep technical expertise and innovation capabilities in the smart sensing field.\\n\\n{/* truncate */}\\n\\nThis national-level recognition is a high affirmation of Heiman\'s specialization, refinement, differentiation, and innovation. Heiman will continue to deepen its focus on smart fire safety, smart gas safety, smart elderly care, and smart sensing, consistently delivering quality products and services to customers.\\n\\nPreviously, Heiman Technology had already received several authoritative qualifications including National High-Tech Enterprise and Guangdong Province Specialized and New SME certifications."}]}}')}}]);